ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  low: { SELECT DISTINCT ?o0 WHERE {
  {
    ?articles a :Articles .
    ?stringers a :Stringers .
    ?articles p:hasStringers ?stringers .
    ?stringers p:name ?fullname .
    BIND(?fullname AS ?o0)
  }
  UNION
  {
    ?articles a :Articles .
    ?editors a :Editors .
    ?articles p:hasEditors ?editors .
    ?editors p:name ?fullname .
    ?articles p:title ?title_f .
    FILTER(STR(?title_f) = "Article 4 Title")
    BIND(?fullname AS ?o0)
  }
} }
  high: { SELECT DISTINCT ?o0 WHERE {
  {
    ?articles a :Articles .
    ?stringers a :Stringers .
    ?articles p:hasStringers ?stringers .
    ?stringers p:name ?fullname .
    ?articles p:title ?title_f .
    FILTER(STR(?title_f) = "Article 4 Title")
    BIND(?fullname AS ?o0)
  }
  UNION
  {
    ?articles a :Articles .
    ?editors a :Editors .
    ?articles p:hasEditors ?editors .
    ?editors p:name ?fullname .
    ?articles p:title ?title_f .
    FILTER(STR(?title_f) = "Article 4 Title")
    BIND(?fullname AS ?o0)
  }
} }
}
